import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class UserInputHandler {

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        // Properly encoding user input before outputting it
        response.getWriter().println("<p>User input: " + encodeHtml(sanitizedInput) + "</p>");
    }

    private String sanitizeInput(String input) {
        // Basic sanitization method to remove potentially harmful characters
        return input.replaceAll("<", "").replaceAll(">", "");
    }

    private String encodeHtml(String input) {
        // Properly encode HTML special characters to prevent XSS
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
